CREATE TABLE IF NOT EXISTS t_p77368943_wiki_bf_debts_starve.wiki_articles (id SERIAL PRIMARY KEY, slug VARCHAR(100) UNIQUE NOT NULL, title VARCHAR(200) NOT NULL, category VARCHAR(50) NOT NULL, icon VARCHAR(10) DEFAULT '📄', rarity VARCHAR(20) DEFAULT 'common', beli_price INTEGER DEFAULT 0, robux_price INTEGER DEFAULT 0, fragment_price INTEGER DEFAULT 0, description TEXT, abilities TEXT, image_url TEXT, created_by INTEGER, updated_by INTEGER, created_at TIMESTAMP DEFAULT NOW(), updated_at TIMESTAMP DEFAULT NOW(), is_published BOOLEAN DEFAULT TRUE, views INTEGER DEFAULT 0);